-- 计算机题库 200 题批量导入脚本
-- 用法：
--   mysql -uexam_user -pchange_me -h127.0.0.1 -P3306 exam_platform < backend/scripts/mysql/seed_computer_200_questions.sql
--
-- 说明：
-- 1) 默认写入 teacher 账号名下；如果 teacher 不存在，则回退到第一个 TEACHER，再回退到第一个 ADMIN。
-- 2) 脚本可重复执行：会先删除同一批次章节下、同一创建人的旧题，再重新插入 200 题。
-- 3) 导入后进入教师端题库，筛选章节“计算机题库200题批量导入”即可查看。

SET NAMES utf8mb4;

SET @chapter_name = '计算机题库200题批量导入';
SET @creator_id = (SELECT id FROM users WHERE username = 'teacher' LIMIT 1);
SET @creator_id = COALESCE(
  @creator_id,
  (SELECT id FROM users WHERE role = 'TEACHER' ORDER BY id LIMIT 1),
  (SELECT id FROM users WHERE role = 'ADMIN' ORDER BY id LIMIT 1)
);

DELETE FROM questions
WHERE chapter = @chapter_name
  AND creator_id = @creator_id;

